	r.MustRegister(NewDOMGetAnchorElement())
	r.MustRegister(NewDOMGetAttributes())
	r.MustRegister(NewDOMGetBoxModel())
	r.MustRegister(NewDOMGetContainerForNode())
	r.MustRegister(NewDOMGetContentQuads())
	r.MustRegister(NewDOMGetDetachedDomNodes())
	r.MustRegister(NewDOMGetDocument())
	r.MustRegister(NewDOMGetElementByRelation())
	r.MustRegister(NewDOMGetFileInfo())
	r.MustRegister(NewDOMGetFlattenedDocument())
	r.MustRegister(NewDOMGetFrameOwner())
	r.MustRegister(NewDOMGetNodeForLocation())
	r.MustRegister(NewDOMGetNodeStackTraces())
	r.MustRegister(NewDOMGetNodesForSubtreeByStyle())
	r.MustRegister(NewDOMGetOuterHTML())
	r.MustRegister(NewDOMGetQueryingDescendantsForContainer())
	r.MustRegister(NewDOMGetRelayoutBoundary())
	r.MustRegister(NewDOMGetSearchResults())
	r.MustRegister(NewDOMGetTopLayerElements())
	r.MustRegister(NewDOMHideHighlight())
	r.MustRegister(NewDOMHighlightNode())
	r.MustRegister(NewDOMHighlightRect())
	r.MustRegister(NewDOMMarkUndoableState())
	r.MustRegister(NewDOMMoveTo())
