	r.MustRegister(NewDOMPushNodeByPathToFrontend())
	r.MustRegister(NewDOMPushNodesByBackendIdsToFrontend())
	r.MustRegister(NewDOMQuerySelector())
	r.MustRegister(NewDOMQuerySelectorAll())
	r.MustRegister(NewDOMRedo())
	r.MustRegister(NewDOMRemoveAttribute())
	r.MustRegister(NewDOMRemoveNode())
	r.MustRegister(NewDOMRequestChildNodes())
	r.MustRegister(NewDOMRequestNode())
